import{_ as e,p as i,q as a,a1 as s}from"./framework-96b046e1.js";const t="/learning-poo/assets/xerox_8010-3fe147f2.jpg",n="/learning-poo/assets/apple_ii-c3cc3a7d.jpg",r="/learning-poo/assets/netscape-3ced1bdf.png",o="/learning-poo/assets/objet-6d96165b.png",l="/learning-poo/assets/com-481489cf.png",d="/learning-poo/assets/classe-4945727f.png",c={},p=s('<h1 id="poo" tabindex="-1"><a class="header-anchor" href="#poo" aria-hidden="true">#</a> POO</h1><h2 id="introduction" tabindex="-1"><a class="header-anchor" href="#introduction" aria-hidden="true">#</a> Introduction</h2><h3 id="histoire" tabindex="-1"><a class="header-anchor" href="#histoire" aria-hidden="true">#</a> Histoire</h3><h4 id="_1970s" tabindex="-1"><a class="header-anchor" href="#_1970s" aria-hidden="true">#</a> 1970s</h4><p><img src="'+t+'" alt="xerox"><img src="'+n+'" alt="apple"></p><ul><li>Développement par Xérox du premier système Fenêtres, Icônes et Souris</li><li>SmallTalk, « archétype » des langages objets</li><li>Développement par Apple des premiers Mac</li></ul><h4 id="_1980s" tabindex="-1"><a class="header-anchor" href="#_1980s" aria-hidden="true">#</a> 1980s</h4><ul><li>Développement des ordinateurs personnels</li><li>Intérêt pour les interfaces graphiques</li><li>Apparition de nouveaux langages tel que le C++, extension de C</li></ul><h4 id="_1990s" tabindex="-1"><a class="header-anchor" href="#_1990s" aria-hidden="true">#</a> 1990s</h4><ul><li>vers une maturité des concepts objets</li><li>Standardisation de C++</li></ul><p><img src="'+r+'" alt="netscape"></p><ul><li>1993 : Montée en puissance du Web grâce à Mosaic</li><li>1995 : Réalisation du logiciel HotJava en Java permettant d’exécuter des applets</li><li>1996 : NetscapeTM Navigator 2 incorpore une machine virtuelle Java 1.0 en version « beta »</li><li>1997 : Un premier pas vers une version industrielle Java 1.1</li><li>1999 : Version industrielle de Java</li></ul><h3 id="objectifs" tabindex="-1"><a class="header-anchor" href="#objectifs" aria-hidden="true">#</a> Objectifs</h3><ul><li>Facilité la réutilisation de code</li><li>Facilité de l’évolution du code</li><li>Améliorer la conception et la maintenance des grands systèmes</li><li>Programmation par « composants ». Conception d’un logiciel à la manière de la fabrication d’une voiture</li></ul><h2 id="principes" tabindex="-1"><a class="header-anchor" href="#principes" aria-hidden="true">#</a> Principes</h2><h3 id="encapsulation" tabindex="-1"><a class="header-anchor" href="#encapsulation" aria-hidden="true">#</a> Encapsulation</h3><p>L&#39;encapsulation est la notion de séparer les parties d&#39;un programme qui sont sensibles à des changements internes et qui doivent être modifiées sans modifier le reste du programme.</p><p>Exemple :</p><ul><li>Un objet de type Voiture possède un attribut nombre de places</li><li>Un objet de type Personne possède un attribut nom</li><li>Un objet de type Personne possède une méthode qui renvoie le nombre de places occupées par cette personne</li></ul><h3 id="polymorphisme" tabindex="-1"><a class="header-anchor" href="#polymorphisme" aria-hidden="true">#</a> Polymorphisme</h3><p>Le polymorphisme est la capacité d&#39;un objet à agir de différentes manières en fonction de son type.</p><p>Exemple :</p><ul><li>Un objet de type Voiture possède une méthode qui renvoie le nombre de places occupées par cette voiture</li></ul><h3 id="objet" tabindex="-1"><a class="header-anchor" href="#objet" aria-hidden="true">#</a> Objet</h3><p><img src="'+o+'" alt="objet"></p><p>Objet est défini par :</p><ul><li>État : représenté par des attributs (variables) qui stockent des valeurs</li><li>Comportement : défini par des méthodes (procédures) qui modifient des états</li><li>Identité : permet de distinguer un objet d’un autre objet</li></ul><h4 id="communication" tabindex="-1"><a class="header-anchor" href="#communication" aria-hidden="true">#</a> Communication</h4><p><img src="'+l+'" alt="communication"></p><ul><li>Les objets communiquent entre eux par des messages</li><li>Un objet peut recevoir un message qui déclenche</li><li>Une méthode qui modifie son état et / ou</li><li>Une méthode qui envoie un message à un autre objet ma voiture le moteur</li></ul><h3 id="la-classe" tabindex="-1"><a class="header-anchor" href="#la-classe" aria-hidden="true">#</a> La Classe</h3><p><img src="'+d+'" alt="classe"></p><ul><li>Les objets qui ont les mêmes états et les mêmes comportements sont regroupés : c’est une classe</li><li>Les classes servent de « moules » pour la création des objets</li><li>Un objet est une instance d’une classe</li><li>Un programme OO est constitué de classes qui permettent de créer des objets qui s’envoient des messages</li></ul><h2 id="🧪-hello-world" tabindex="-1"><a class="header-anchor" href="#🧪-hello-world" aria-hidden="true">#</a> 🧪 Hello World</h2><ul><li>À l’aide de l’IDE en ligne <a href="www.onlinegdb.com">online GDB</a></li><li>Compilez votre première classe Voiture.</li></ul>',35),u=[p];function h(m,b){return i(),a("div",null,u)}const f=e(c,[["render",h],["__file","index.html.vue"]]);export{f as default};
